	SetAgentRole(context.Context, *SetAgentRoleRequest) (*SetAgentRoleResponse, error)
	RemoveAgentRole(context.Context, *RemoveAgentRoleRequest) (*RemoveAgentRoleResponse, error)
	ListAgentRoles(context.Context, *ListAgentRolesRequest) (*ListAgentRolesResponse, error)
	ListMyAgentRoles(context.Context, *ListMyAgentRolesRequest) (*ListMyAgentRolesResponse, error)
	// --- Volumes ---
	CreateVolume(context.Context, *CreateVolumeRequest) (*CreateVolumeResponse, error)
	GetVolume(context.Context, *GetVolumeRequest) (*GetVolumeResponse, error)
	UpdateVolume(context.Context, *UpdateVolumeRequest) (*UpdateVolumeResponse, error)
	DeleteVolume(context.Context, *DeleteVolumeRequest) (*DeleteVolumeResponse, error)
	ListVolumes(context.Context, *ListVolumesRequest) (*ListVolumesResponse, error)
