	CreateVolumeAttachment(context.Context, *CreateVolumeAttachmentRequest) (*CreateVolumeAttachmentResponse, error)
	GetVolumeAttachment(context.Context, *GetVolumeAttachmentRequest) (*GetVolumeAttachmentResponse, error)
	DeleteVolumeAttachment(context.Context, *DeleteVolumeAttachmentRequest) (*DeleteVolumeAttachmentResponse, error)
	ListVolumeAttachments(context.Context, *ListVolumeAttachmentsRequest) (*ListVolumeAttachmentsResponse, error)
	// --- MCPs ---
	CreateMcp(context.Context, *CreateMcpRequest) (*CreateMcpResponse, error)
	GetMcp(context.Context, *GetMcpRequest) (*GetMcpResponse, error)
	UpdateMcp(context.Context, *UpdateMcpRequest) (*UpdateMcpResponse, error)
	DeleteMcp(context.Context, *DeleteMcpRequest) (*DeleteMcpResponse, error)
	ListMcps(context.Context, *ListMcpsRequest) (*ListMcpsResponse, error)
	// --- Skills ---
	CreateSkill(context.Context, *CreateSkillRequest) (*CreateSkillResponse, error)
	GetSkill(context.Context, *GetSkillRequest) (*GetSkillResponse, error)
	UpdateSkill(context.Context, *UpdateSkillRequest) (*UpdateSkillResponse, error)
	DeleteSkill(context.Context, *DeleteSkillRequest) (*DeleteSkillResponse, error)
	ListSkills(context.Context, *ListSkillsRequest) (*ListSkillsResponse, error)
	// --- Hooks ---
	CreateHook(context.Context, *CreateHookRequest) (*CreateHookResponse, error)
	GetHook(context.Context, *GetHookRequest) (*GetHookResponse, error)
	UpdateHook(context.Context, *UpdateHookRequest) (*UpdateHookResponse, error)
	DeleteHook(context.Context, *DeleteHookRequest) (*DeleteHookResponse, error)
	ListHooks(context.Context, *ListHooksRequest) (*ListHooksResponse, error)
	// --- Envs ---
	CreateEnv(context.Context, *CreateEnvRequest) (*CreateEnvResponse, error)
	GetEnv(context.Context, *GetEnvRequest) (*GetEnvResponse, error)
	UpdateEnv(context.Context, *UpdateEnvRequest) (*UpdateEnvResponse, error)
	DeleteEnv(context.Context, *DeleteEnvRequest) (*DeleteEnvResponse, error)
	ListEnvs(context.Context, *ListEnvsRequest) (*ListEnvsResponse, error)
	// --- Init Scripts ---
	CreateInitScript(context.Context, *CreateInitScriptRequest) (*CreateInitScriptResponse, error)
	GetInitScript(context.Context, *GetInitScriptRequest) (*GetInitScriptResponse, error)
	UpdateInitScript(context.Context, *UpdateInitScriptRequest) (*UpdateInitScriptResponse, error)
	DeleteInitScript(context.Context, *DeleteInitScriptRequest) (*DeleteInitScriptResponse, error)
